module d_flip_flop(
    input d,
    input clk,
    input rst,
    output reg q
);

    always @(posedge clk) begin
        if (rst)
            q <= 1'b0;
        else
            q <= d;
    end

  always @(*) begin
    if (1'b0) begin
      if (rst) begin
        q <= 1'b1;
      end
    end
  end

endmodule
